Output:
<#
.SYNOPSIS
    Codex CLI 단일 호출 헬퍼. Claude Code / Codex 양쪽에서 호출 가능.
.DESCRIPTION
    - 프롬프트를 받아 프로젝트 컨텍스트(CLAUDE.md, anti_patterns, Feature README)를 자동 포함
    - -Context 파라미터로 이전 라운드 내용을 누적 전달 (라이브 토론용)
    - 응답을 stdout으로 반환, 선택적으로 파일 저장
.EXAMPLE
    .\tools\invoke-codex.ps1 -Prompt "SkillData를 SO로 바꿔야 할까?"
    .\tools\invoke-codex.ps1 -PromptFile .\task.txt -Save
    .\tools\invoke-codex.ps1 -Prompt "이 설계 리뷰해줘" -Context "이전 라운드 내용..."
#>
[CmdletBinding()]
param(
    [string]$Prompt = "",
    [string]$PromptFile = "",
    [string]$Context = "",
    [string]$CodexModel = "",
    [string]$CodexPath = "",
    [string]$OutputFile = "",
    [string]$WorkingDirectory = "",
    [string]$CodexHome = "",
    [switch]$Save,
    [switch]$NoProjectContext,
    [switch]$Ephemeral
)

$ErrorActionPreference = "Stop"
$scriptDir = if ($PSScriptRoot) { $PSScriptRoot } else { Split-Path -Parent $MyInvocation.MyCommand.Definition }
$repoRoot = (git -C $scriptDir rev-parse --show-toplevel 2>$null)
if (-not $repoRoot) { $repoRoot = Split-Path $scriptDir }
if (-not $WorkingDirectory) { $WorkingDirectory = $repoRoot }
if (-not $CodexHome) { $CodexHome = Join-Path $repoRoot ".codex-local" }

# ── Resolve codex executable (skip .ps1 wrapper) ──

function Resolve-CodexExecutable {
    param([string]$PreferredPath)

    $candidates = New-Object System.Collections.Generic.List[string]

    # Explicit path
    if ($PreferredPath -and (Test-Path $PreferredPath)) { $candidates.Add((Resolve-Path $PreferredPath).Path) }

    # Env override
    if ($env:CODEX_PATH -and (Test-Path $env:CODEX_PATH)) { $candidates.Add((Resolve-Path $env:CODEX_PATH).Path) }

    # PATH lookup
    foreach ($name in @("codex.exe", "codex.cmd", "codex")) {
        $cmd = Get-Command $name -ErrorAction SilentlyContinue | Select-Object -First 1
        if ($cmd -and $cmd.Source) { $candidates.Add($cmd.Source) }
    }

    # npm global
    foreach ($leaf in @("npm\codex.cmd", "npm\codex.exe")) {
        $p = Join-Path $env:APPDATA $leaf
        if (Test-Path $p) { $candidates.Add($p) }
    }

    # VS Code extension embedded binary
    $extDir = Join-Path $env:USERPROFILE ".vscode\extensions"
    if (Test-Path $extDir) {
        Get-ChildItem $extDir -Directory -Filter "openai.chatgpt-*" | Sort-Object Name -Descending | ForEach-Object {
            $exe = Join-Path $_.FullName "bin\windows-x86_64\codex.exe"
            if (Test-Path $exe) { $candidates.Add($exe) }
        }
    }

    # Deduplicate, skip .ps1
    $seen = @{}
    foreach ($c in $candidates) {
        if ([string]::IsNullOrWhiteSpace($c)) { continue }
        $key = $c.ToLowerInvariant()
        if ($seen.ContainsKey($key)) { continue }
        $seen[$key] = $true
        if (-not (Test-Path $c)) { continue }
        if ([IO.Path]::GetExtension($c) -ieq ".ps1") { continue }
        return $c
    }

    throw "Codex executable not found. Pass -CodexPath or install @openai/codex."
}

# ── Input validation ──

if (-not $Prompt -and -not $PromptFile) { throw "Either -Prompt or -PromptFile is required." }
if ($PromptFile) {
    if (-not (Test-Path $PromptFile)) { throw "Prompt file not found: $PromptFile" }
    $Prompt = Get-Content -Path $PromptFile -Raw -Encoding UTF8
}

$codexExe = Resolve-CodexExecutable $CodexPath

# ── Build project context ──

$projectContext = ""
if (-not $NoProjectContext) {
    $parts = @()

    $claudeMdPath = Join-Path $repoRoot "CLAUDE.md"
    if (Test-Path $claudeMdPath) {
        $parts += "# Project Rules`n" + (Get-Content $claudeMdPath -Raw -Encoding UTF8).TrimEnd()
    }

    $antiPath = Join-Path $repoRoot "agent/anti_patterns.md"
    if (Test-Path $antiPath) {
        $parts += "# Anti Patterns`n" + (Get-Content $antiPath -Raw -Encoding UTF8).TrimEnd()
    }

    foreach ($m in [regex]::Matches($Prompt, 'Features/(\w+)')) {
        $feat = $m.Groups[1].Value
        $readmePath = Join-Path $repoRoot "Assets/Scripts/Features/$feat/README.md"
        if (Test-Path $readmePath) {
            $parts += "# $feat README`n" + (Get-Content $readmePath -Raw -Encoding UTF8).TrimEnd()
        }
    }

    if ($parts.Count -gt 0) {
        $projectContext = $parts -join "`n`n---`n`n"
    }
}

# ── Assemble full prompt ──

$sections = @()
if ($projectContext) { $sections += $projectContext }
if ($Context) { $sections += "# Prior Discussion`n$Context" }
$sections += "# Request`n$Prompt"

$fullPrompt = $sections -join "`n`n---`n`n"

# ── Call codex exec ──

$tempOut = Join-Path $env:TEMP ("invoke-codex-{0}.txt" -f (Get-Date -Format "yyyyMMdd-HHmmssfff"))

$execArgs = @("exec", "--sandbox", "read-only", "--color", "never", "-C", $WorkingDirectory, "-o", $tempOut)
if ($Ephemeral) { $execArgs += "--ephemeral" }
if ($CodexModel) { $execArgs += @("-m", $CodexModel) }
$execArgs += "-"

$prevHome = $env:CODEX_HOME
$env:CODEX_HOME = $CodexHome
New-Item -ItemType Directory -Path $CodexHome -Force | Out-Null

# ── Ensure auth.json exists in CODEX_HOME ──
$localAuth = Join-Path $CodexHome "auth.json"
if (-not (Test-Path $localAuth)) {
    $defaultAuth = Join-Path $env:USERPROFILE ".codex/auth.json"
    if (Test-Path $defaultAuth) {
        Copy-Item $defaultAuth $localAuth
        Write-Host "[invoke-codex] Copied auth.json from ~/.codex/ to $CodexHome" -ForegroundColor Yellow
    }
}

try {
    # Codex CLI writes its version banner to stderr, which PowerShell treats as
    # a terminating error under $ErrorActionPreference = "Stop". Temporarily
    # switch to Continue so stderr is captured instead of thrown.
    $prevEAP = $ErrorActionPreference
    $ErrorActionPreference = "Continue"
    $rawOutput = $fullPrompt | & $codexExe @execArgs 2>&1
    $exitCode = $LASTEXITCODE
    $ErrorActionPreference = $prevEAP
}
finally {
    if ($null -eq $prevHome) { Remove-Item Env:CODEX_HOME -ErrorAction SilentlyContinue }
    else { $env:CODEX_HOME = $prevHome }
}

if ($exitCode -ne 0 -or -not (Test-Path $tempOut)) {
    $allOutput = ($rawOutput | ForEach-Object { "$_" }) -join "`n"

    # ── Diagnose common failure causes ──
    $diagnosis = ""
    if ($allOutput -match "(?i)ENOTFOUND|ECONNREFUSED|ETIMEDOUT|network|socket hang up|fetch failed") {
        $diagnosis = "Network: api.openai.com 또는 wss://api.openai.com 연결 실패. 방화벽/프록시/VPN을 확인하세요."
    }
    elseif ($allOutput -match "(?i)401|unauthorized|invalid.*key|authentication") {
        $diagnosis = "Auth: OPENAI_API_KEY가 설정되지 않았거나 만료됨. 환경변수를 확인하세요."
    }
    elseif ($allOutput -match "(?i)429|rate.?limit|too many requests") {
        $diagnosis = "Rate limit: API 요청 한도 초과. 잠시 후 재시도하세요."
    }
    elseif ($allOutput -match "(?i)EACCES|permission|access.*denied") {
        $diagnosis = "Permission: CODEX_HOME($CodexHome) 또는 temp 디렉토리 쓰기 권한 문제."
    }
    elseif ($allOutput -match "(?i)ENOSPC|disk.*full|no space") {
        $diagnosis = "Disk: 디스크 공간 부족."
    }

    $tail = ($rawOutput | Select-Object -Last 30) -join "`n"

    $errorMsg = "[invoke-codex] FAILED`n"
    $errorMsg += "  Exit code : $exitCode`n"
    $errorMsg += "  Executable: $codexExe`n"
    $errorMsg += "  CODEX_HOME: $CodexHome`n"
    $errorMsg += "  Output file exists: $(Test-Path $tempOut)`n"
    if ($diagnosis) {
        $errorMsg += "`n  >> Diagnosis: $diagnosis`n"
    }
    $errorMsg += "`n--- Last 30 lines ---`n$tail"

    throw $errorMsg
}

$response = Get-Content $tempOut -Raw -Encoding UTF8
Remove-Item $tempOut -Force -ErrorAction SilentlyContinue

# ── Output ──

if ($Save -or $OutputFile) {
    $artifactsDir = Join-Path $scriptDir "artifacts"
    if (-not (Test-Path $artifactsDir)) {
        New-Item -ItemType Directory -Path $artifactsDir -Force | Out-Null
    }
    if (-not $OutputFile) {
        $OutputFile = Join-Path $artifactsDir "codex-response-$(Get-Date -Format 'yyyyMMdd-HHmmss').md"
    }
    $response | Out-File -FilePath $OutputFile -Encoding UTF8 -NoNewline
    Write-Host "[invoke-codex] Saved: $OutputFile" -ForegroundColor Green
}

Write-Output $response
